import React from "react";
import trash from "../trash.svg";
import { data } from "react-router-dom";
import { useCart, useDispatchCart } from "../components/ContextReducer";
function Cart() {
  let data = useCart();
  let dispatch = useDispatchCart();
  if (data.length === 0) {
    return (
      <div>
        <div className="m-5 w-100 text-center fs-3 text-success">
          The Cart is Empty!
        </div>
      </div>
    );
  }
  let totalPrice = data.reduce((total, food) => total + food.price, 0);
  return (
    <div>
      <div className="container m-auto mt-5 table-responsive  table-responsive-sm table-responsive-md">
        <table className="table table-hover ">
          <thead className=" fs-4 ">
            <tr>
              <th scope="col" className="text-success">
                #
              </th>
              <th scope="col" className="text-success">
                Name
              </th>
              <th scope="col" className='text-success'>Quantity</th>
              <th scope="col" className='text-success'>Option</th>
              <th scope="col"className='text-success'>Amount</th>
              <th scope="col"></th>
            </tr>
          </thead>
          <tbody>
            {data.map((food, index) => (
              <tr className="">
                <th scope="row">{index + 1}</th>
                <td>{food.name}</td>
                <td>{food.qty}</td>
                <td>{food.size}</td>
                <td>{food.price}</td>
                <td>
                  <button type="button" className="btn p-0">
                    <img
                      src={trash}
                      alt="delete"
                      onClick={() => dispatch({ type: "REMOVE", index })}
                      style={{ height: "20px" }}
                    />
                  </button>{" "}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
        <div>
          <h1 className="fs-2">Total Price: {totalPrice}/-</h1>
        </div>
        <div>
          <button className="btn bg-success mt-5">Check Out</button>
        </div>
      </div>
    </div>
  );
}

export default Cart;
